// Backward-compatible re-exports. The branches write layer now lives in the resource module
// (`@/lib/api/resources/branches`), generated by `createResourceApi` (create/update/delete each
// invalidate the branches namespace on success). These aliases keep existing importers working; new
// resources should call `branchesApi.useCreate()` etc. directly. Remove this shim once every branches
// consumer imports from the resource module.
import { branchesApi } from "@/lib/api/resources/branches";

export const useCreateBranch = branchesApi.useCreate;
export const useUpdateBranch = branchesApi.useUpdate;
export const useDeleteBranch = branchesApi.useDelete;
